import React, { useState, useMemo } from "react";
import {
  Container,
  Row,
  Col,
  Form,
  Button,
  Card,
  ListGroup,
} from "react-bootstrap";
import { useProvider } from "./useProvider";

const Movies = () => {
  const { producers } = useProvider();
  const producerName = [...new Set(producers?.map((p) => p.name))];

  return (
    <Container>
      <h1>React Application</h1>
      <hr />
      <div>---</div>
      <hr />
      <Row>
        <Col xs={3}>
          <h2>Producers</h2>

          {producerName?.map((p) => (
            <li key={p}>
              <a href="/">{p}</a>
            </li>
          ))}
        </Col>

        <Col xs={9}>
          <h2>List of movies</h2>
        </Col>
      </Row>
    </Container>
  );
};

export default Movies;
